<script setup lang="ts">
import { computed,onMounted,ref } from 'vue'; import { showFailToast } from 'vant'; import PageHeader from '../components/PageHeader.vue'; import EmptyState from '../components/EmptyState.vue'; import { useAuthStore } from '../stores/auth'; import { getActiveActivity,getRecords } from '../services/api'; import type { DailyRecord } from '../types'; import { formatCN } from '../utils/date'
const auth=useAuthStore(); const records=ref<DailyRecord[]>([]); const range=ref<string[]>([]); const show=ref(false)
const filtered=computed(()=>records.value.filter(r=>!range.value.length||(r.record_date>=range.value[0]&&r.record_date<=range.value[1])))
onMounted(async()=>{try{if(!auth.user)return;const {activity}=await getActiveActivity(auth.user.id);if(activity)records.value=await getRecords(auth.user.id,activity.id)}catch(e){showFailToast(e instanceof Error?e.message:'加载失败')}})
</script>
<template><section class="page"><PageHeader eyebrow="MY JOURNEY" title="历史记录"/><div class="card row" @click="show=true"><span>{{range.length?`${range[0]} 至 ${range[1]}`:'全部日期'}}</span><van-icon name="calendar-o"/></div><div class="card"><EmptyState v-if="!filtered.length" text="还没有打卡记录"/><article v-for="(r,i) in filtered" :key="r.id" class="record"><div class="row"><strong>{{formatCN(r.record_date)}}</strong><span class="tag">{{r.completed?'已完成':'未完成'}}</span></div><div class="row" style="margin-top:10px"><span><b>{{r.weight}} kg</b><small class="muted"> · {{r.exercised?`${r.exercise_type||'运动'} ${r.exercise_minutes} 分钟`:'未运动'}}</small></span><span v-if="filtered[i+1]" :style="{color:filtered[i+1].weight-r.weight>=0?'#1f765c':'#b75a4e'}">{{(filtered[i+1].weight-r.weight).toFixed(1)}} kg</span></div><p v-if="r.remark" class="muted">{{r.remark}}</p></article></div><van-calendar v-model:show="show" type="range" @confirm="(v:any)=>{range=[v[0].toLocaleDateString('en-CA'),v[1].toLocaleDateString('en-CA')];show=false}"/></section></template>
